package com.google.gson;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.lang.reflect.Field;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

class GsonBuilderTest {

  private GsonBuilder gsonBuilder;

  @BeforeEach
  void setUp() {
    gsonBuilder = new GsonBuilder();
  }

  @Test
  void setFieldNamingStrategy_shouldSetFieldNamingStrategy_whenNotNull() throws Exception {
    FieldNamingStrategy mockStrategy = mock(FieldNamingStrategy.class);

    GsonBuilder returned = gsonBuilder.setFieldNamingStrategy(mockStrategy);

    assertSame(gsonBuilder, returned);

    // Access private field fieldNamingPolicy using reflection to verify it was set correctly
    Field field = GsonBuilder.class.getDeclaredField("fieldNamingPolicy");
    field.setAccessible(true);
    Object fieldValue = field.get(gsonBuilder);
    assertSame(mockStrategy, fieldValue);
  }

  @Test
  void setFieldNamingStrategy_shouldThrowNullPointerException_whenNull() {
    assertThrows(NullPointerException.class, () -> gsonBuilder.setFieldNamingStrategy(null));
  }
}
